];

// Mock API implementation
const mockAPI = {
  // Simulate network delay
  delay: (ms = 500) => new Promise(resolve => setTimeout(resolve, ms)),

  // Login
  login: async (credentials) => {
    console.log('🔐 Mock API - Login attempt:', credentials);
    await mockAPI.delay(800);
    
    const { userName, password } = credentials;
    const user = mockUsers.find(u => u.userName === userName && u.password === password);
    
    if (!user) {
      console.log('❌ Mock API - Login failed: Invalid credentials');
      throw new Error('Invalid credentials');
    }
    
    const token = `mock_token_${user.userName}_${Date.now()}`;
    console.log('✅ Mock API - Login successful:', { userName: user.userName, role: user.role });
    
    return {
      token,
      user: {
        userName: user.userName,
        name: user.name,
        email: user.email,
        role: user.role,
        status: user.status
      },
      forcePasswordChange: user.forcePasswordChange
    };
  },

  // Get user profile
  getProfile: async () => {
    console.log('👤 Mock API - Get profile request');
    await mockAPI.delay(300);
    
    // Extract user from token (simplified)
    const token = localStorage.getItem('token');
    if (!token) {
      throw new Error('No token found');
    }
    
    // Parse token to get username (mock implementation)
    const userName = token.split('_')[2];
    const user = mockUsers.find(u => u.userName === userName);
    
    if (!user) {
      throw new Error('User not found');
    }
    
    console.log('✅ Mock API - Profile retrieved:', { userName: user.userName, role: user.role });
    return {
      userName: user.userName,
      name: user.name,
      email: user.email,
      role: user.role,
      status: user.status,
      forcePasswordChange: user.forcePasswordChange
    };
  },

  // Register user
  register: async (userData) => {
    console.log('📝 Mock API - Registration attempt:', userData);
    await mockAPI.delay(1000);
    
    // Check if user already exists
    const existingUser = mockUsers.find(u => u.userName === userData.userName || u.email === userData.email);
    if (existingUser) {
      throw new Error('User already exists');
    }
    
    const newUser = {
      id: mockUsers.length + 1,
      ...userData,
      status: 'PENDING',
      forcePasswordChange: false
    };
    
    mockUsers.push(newUser);
    console.log('✅ Mock API - Registration successful');
    
    return {
      message: 'Registration successful',
      user: newUser
    };
  },

  // Send OTP
  sendOTP: async (email) => {
    console.log('📧 Mock API - Send OTP to:', email);
    await mockAPI.delay(500);
    
    console.log('✅ Mock API - OTP sent successfully (mock OTP: 123456)');
    return {
      message: 'OTP sent successfully',
      otp: '123456' // Mock OTP for testing
    };
  },

  // Verify OTP
  verifyOTP: async (otpData) => {
    console.log('🔍 Mock API - Verify OTP:', otpData);
    await mockAPI.delay(300);
    
    if (otpData.otp === '123456') {
      console.log('✅ Mock API - OTP verified successfully');
      return {
        message: 'OTP verified successfully',
        verified: true
      };
    } else {
      console.log('❌ Mock API - OTP verification failed');
      throw new Error('Invalid OTP');
    }
  },

  // Resend OTP
  resendOTP: async (email) => {
    console.log('🔄 Mock API - Resend OTP to:', email);
    await mockAPI.delay(500);
    
    console.log('✅ Mock API - OTP resent successfully (mock OTP: 123456)');
    return {
      message: 'OTP resent successfully',
      otp: '123456'
    };
  },

  // Forgot password
  forgotPassword: async (email) => {
